/* statMgmtMapper.getInvPymPrdCheck */
SELECT COUNT(1) CNT FROM DUAL
WHERE   TO_CHAR(ADD_MONTHS(TO_DATE(#{endYm}, 'YYYYMM'), -60), 'YYYYMM')  <  #{strtYm}

mapper.insert:
/* statMgmtMapper.callInvPymData */
{ CALL P_ACNT_DATA_PROC(
				#{trgtYm, mode=IN, jdbcType=VARCHAR}
				, #{strtYm, mode=IN, jdbcType=VARCHAR}
				, #{endYm, mode=IN, jdbcType=VARCHAR}
				, #{userId, mode=IN, jdbcType=VARCHAR}
				, #{reqId, mode=OUT, jdbcType=VARCHAR}
				, #{errCode, mode=OUT, jdbcType=VARCHAR}
				, #{errMsg, mode=OUT, jdbcType=VARCHAR}
	) }

