mapper.select:
/* statMgmtMapper.selectBillDatFile */ SELECT B.OPRT_FILE_NM AS fileNm FROM CMN_JUICE_BATCH_MST CJBM , (SELECT CJBD.OPRT_DT , CJBD.OPRT_SCTN_CD , CJBD.OPRT_SEQ , CJBD.OPRT_FILE_NM , OPRT_SUCC_DATA_CNT FROM CMN_JUICE_BATCH_DTL CJBD WHERE CJBD.OPRT_MOD = 'S') B , (SELECT CGCM.CD_VAL , CGCM.CD_DSC , CGCM.ETC1 FROM CMN_GRP_MST CGM , CMN_GRP_CD_MST CGCM WHERE CGM.GRP_ID = CGCM.GRP_ID AND CGM.GRP_ID = 'CMN0109' AND CGM.USG_YN = 'Y' AND CGCM.USG_YN = 'Y') CMN WHERE 1=1 AND CJBM.OPRT_DT = B.OPRT_DT(+) AND CJBM.OPRT_SCTN_CD = B.OPRT_SCTN_CD(+) AND CJBM.OPRT_SEQ = B.OPRT_SEQ(+) AND CJBM.OPRT_SCTN_CD = CMN.CD_VAL
AND CJBM.OPRT_SCTN_CD = #{oprtSctnCd, jdbcType=VARCHAR}
AND CJBM.OPRT_DT BETWEEN #{oprtStrtDt, jdbcType=VARCHAR} AND #{oprtEndDt, jdbcType=VARCHAR}
AND CJBM.OPRT_STAT_CD = #{oprtStatCd, jdbcType=VARCHAR}
AND CJBM.OPRT_SUCC_DATA_CNT > 0
ORDER BY OPRT_STRT_DT DESC

